def row(n):
    dist = {}
    def dfs(v, used, vis, d):
        for u in range(n):
            e = v * n + u; nv = vis | (1 << u)
            if (used >> e) & 1:
                if nv == (1 << n) - 1:
                    dist[d + 1] = dist.get(d + 1, 0) + 1
            else:
                dfs(u, used | (1 << e), nv, d + 1)
    for u in range(n):
        dfs(u, 1 << u, (1 << 0) | (1 << u), 1)
    return [dist.get(k, 0) for k in range(n + 1, n * n + 2)]
# [row(n) for n in range(1, 5)] gives first 4 rows

